import{_ as a,c as t,o as r,ak as i,ao as s}from"./chunks/framework.BZBtq1Ev.js";const m=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v2-46-0.md","filePath":"aireblock-releases/aireframe-v2-46-0.md","lastUpdated":1777466790000}'),o={name:"aireblock-releases/aireframe-v2-46-0.md"};function n(l,e,c,p,u,d){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+s+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.46.0<br><strong>Release Date:</strong> 6th May 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Tenant Theme Colours in Liquid Expressions (FRAME-2443)</li><li>Subject Group Management APIs (FRAME-2512, FRAME-2513, FRAME-2514, FRAME-2515, FRAME-2516)</li><li>GraphQL Alias Overloading Protection (FRAME-2532)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>In-Browser Subject Avatar Cropping (FRAME-1559)</li><li>Delete Structural Entity API (FRAME-2508)</li><li>Query Groups API (FRAME-2509)</li><li>Get Group by Key API (FRAME-2510)</li><li>Delete Group API (FRAME-2511)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Blocked JavaScript-Embedded PDF Uploads (FRAME-2534)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="tenant-theme-colours-in-liquid-expressions-frame-2443" tabindex="-1">Tenant Theme Colours in Liquid Expressions (FRAME-2443) <a class="header-anchor" href="#tenant-theme-colours-in-liquid-expressions-frame-2443" aria-label="Permalink to “Tenant Theme Colours in Liquid Expressions (FRAME-2443)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Tenant theme colours are now accessible within Liquid expressions via the <code>tenant.theme.colours</code> object, enabling dynamic, theme-aware content rendering.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now reference your organisation&#39;s theme colours directly in templates and expressions, making it easier to produce on-brand content without hardcoding colour values.</p></div><hr><h4 id="subject-group-upsert-api-frame-2512" tabindex="-1">Subject Group Upsert API (FRAME-2512) <a class="header-anchor" href="#subject-group-upsert-api-frame-2512" aria-label="Permalink to “Subject Group Upsert API (FRAME-2512)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint has been added to create or update groups, supporting the full subject ownership model introduced in this release.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Developers integrating with AireFrame can now programmatically manage groups, streamlining how organisations structure and assign subject ownership.</p></div><hr><h4 id="query-structure-types-api-frame-2513" tabindex="-1">Query Structure Types API (FRAME-2513) <a class="header-anchor" href="#query-structure-types-api-frame-2513" aria-label="Permalink to “Query Structure Types API (FRAME-2513)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new paginated API endpoint has been introduced to query all structure types defined within a tenant, following the same pagination pattern as the structural entities API.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You now have a consistent, paginated way to retrieve structure type definitions via the API, making it easier to build integrations that reflect your data model.</p></div><hr><h4 id="get-structure-type-by-key-api-frame-2514" tabindex="-1">Get Structure Type by Key API (FRAME-2514) <a class="header-anchor" href="#get-structure-type-by-key-api-frame-2514" aria-label="Permalink to “Get Structure Type by Key API (FRAME-2514)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint has been added to retrieve a specific structure type by its key, mirroring the existing structural entity lookup pattern.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now look up individual structure types directly by key through the API, reducing the need for multiple requests when working with known type identifiers.</p></div><hr><h4 id="upsert-structure-type-api-frame-2515" tabindex="-1">Upsert Structure Type API (FRAME-2515) <a class="header-anchor" href="#upsert-structure-type-api-frame-2515" aria-label="Permalink to “Upsert Structure Type API (FRAME-2515)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint allows structure types to be created or updated in a single operation, supporting the subject ownership feature set.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Developers can now manage structure type definitions programmatically, enabling more automated and repeatable configuration of your AireFrame environment.</p></div><hr><h4 id="delete-structure-type-api-frame-2516" tabindex="-1">Delete Structure Type API (FRAME-2516) <a class="header-anchor" href="#delete-structure-type-api-frame-2516" aria-label="Permalink to “Delete Structure Type API (FRAME-2516)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint has been introduced to delete structure types by key, completing the full set of structure type management operations.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You now have full create, read, update, and delete control over structure types via the API, giving developers and integrators complete lifecycle management.</p></div><hr><h4 id="graphql-alias-overloading-protection-frame-2532" tabindex="-1">GraphQL Alias Overloading Protection (FRAME-2532) <a class="header-anchor" href="#graphql-alias-overloading-protection-frame-2532" aria-label="Permalink to “GraphQL Alias Overloading Protection (FRAME-2532)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A fix has been applied to address a GraphQL alias overloading vulnerability identified during penetration testing. This hardens the API against denial-of-service attacks that exploit alias-based query amplification.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>The AireFrame API is now more resilient against a class of abuse that could degrade performance for all users, improving overall platform stability and security.</p></div><hr><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="in-browser-subject-avatar-cropping-frame-1559" tabindex="-1">In-Browser Subject Avatar Cropping (FRAME-1559) <a class="header-anchor" href="#in-browser-subject-avatar-cropping-frame-1559" aria-label="Permalink to “In-Browser Subject Avatar Cropping (FRAME-1559)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Users can now crop subject avatar images directly within the browser rather than needing to pre-crop images before uploading.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Uploading and setting a subject avatar is now simpler — you can adjust the crop in-browser without needing to use an external image editor first.</p></div><hr><h4 id="delete-structural-entity-api-frame-2508" tabindex="-1">Delete Structural Entity API (FRAME-2508) <a class="header-anchor" href="#delete-structural-entity-api-frame-2508" aria-label="Permalink to “Delete Structural Entity API (FRAME-2508)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint is now available for deleting structural entities, expanding the structural entity management surface.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now remove structural entities via the API, giving integrators full control over the lifecycle of structural data within AireFrame.</p></div><hr><h4 id="query-groups-api-frame-2509" tabindex="-1">Query Groups API (FRAME-2509) <a class="header-anchor" href="#query-groups-api-frame-2509" aria-label="Permalink to “Query Groups API (FRAME-2509)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A paginated API endpoint has been introduced to query groups, consistent with the paging pattern used across other AireFrame list APIs.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Developers can now retrieve and page through groups via the API, making it straightforward to build integrations that work with your group structure.</p></div><hr><h4 id="get-group-by-key-api-frame-2510" tabindex="-1">Get Group by Key API (FRAME-2510) <a class="header-anchor" href="#get-group-by-key-api-frame-2510" aria-label="Permalink to “Get Group by Key API (FRAME-2510)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint allows retrieval of a specific subject group by its key. Requests for the internal global group key will return a 404 as it is not a manageable group.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can look up individual groups directly by key through the API, which reduces unnecessary requests when working with known group identifiers.</p></div><hr><h4 id="delete-group-api-frame-2511" tabindex="-1">Delete Group API (FRAME-2511) <a class="header-anchor" href="#delete-group-api-frame-2511" aria-label="Permalink to “Delete Group API (FRAME-2511)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new API endpoint has been added to delete groups, completing the core CRUD operations for group management.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Developers and integrators now have full create, read, update, and delete capability for groups via the API.</p></div><hr><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="blocked-javascript-embedded-pdf-uploads-frame-2534" tabindex="-1">Blocked JavaScript-Embedded PDF Uploads (FRAME-2534) <a class="header-anchor" href="#blocked-javascript-embedded-pdf-uploads-frame-2534" aria-label="Permalink to “Blocked JavaScript-Embedded PDF Uploads (FRAME-2534)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireFrame now rejects uploaded PDF files that contain embedded JavaScript, addressing a stored cross-site scripting (XSS) vulnerability identified during penetration testing. PDFs with JavaScript keywords or action markers are blocked at the point of upload with an appropriate error message.</p></div><hr><h4 id="fixed-json-schema-concurrency-errors-frame-2555" tabindex="-1">Fixed JSON Schema Concurrency Errors (FRAME-2555) <a class="header-anchor" href="#fixed-json-schema-concurrency-errors-frame-2555" aria-label="Permalink to “Fixed JSON Schema Concurrency Errors (FRAME-2555)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A concurrency issue in the JSON schema processing library was causing intermittent errors under concurrent load, resulting in unhandled exceptions in production.</p></div>',70)])])}const b=a(o,[["render",n]]);export{m as __pageData,b as default};
